    string sortString(string s) {
        string res;
        sort(s.begin(), s.end());
        while (!s.empty()) {
            res += s.back();
            s.pop_back();
            string temp;
            for (char c : s) {
                if (c < res.back()) {
                    temp += c;
                }
            }
            s = temp;
            temp.clear();
            while (!s.empty() && s.back() < res.back()) {
                res += s.back();
                s.pop_back();
            }
        }
        return res;
    }
};```
